mapper.select:
select 
from (
  (
    select 
    from t_drone_location
    where uas_id = #{uasId,jdbcType=VARCHAR}
      and get_location_timestamp < #{getLocationTimestamp,jdbcType=TIMESTAMP}
    order by get_location_timestamp desc
    limit 1
  )
  union all
  (
    select 
    from t_drone_location
    where reservation_id = #{reservationId,jdbcType=VARCHAR}
      and get_location_timestamp < #{getLocationTimestamp,jdbcType=TIMESTAMP}
    order by get_location_timestamp desc
    limit 1
  )
) as candidates
order by get_location_timestamp desc
limit 1

select ar.*, rd.aircraft_info_id
from t_remote_data rd
join t_uasl_reservation ar
on rd.uasl_reservation_id = ar.uasl_reservation_id
where (rd.serial_number = #{uasId,jdbcType=VARCHAR}
or rd.registration_id = #{uasId,jdbcType=VARCHAR}
or rd.utm_id = #{uasId,jdbcType=VARCHAR}
or rd.specific_session_id = #{uasId,jdbcType=VARCHAR}
or ar.uasl_reservation_id = #{reservationId,jdbcType=VARCHAR})
and #{getLocationTimestamp,jdbcType=TIMESTAMP}
between ar.start_at
and ar.end_at

select dl.get_location_timestamp, dl.subscription_id, dl.ua_type, dl.latitude, dl.longitude, dl.altitude, dl.track_direction, dl.speed, dl.vertical_speed, dl.route_deviation_rate, dl.route_deviation_rate_update_time, dl.reservation_id, dl.uasl_id, dl.uasl_section_id, dl.operational_status, dl.operator_id, dl.flight_time, dl.aircraft_info_id, rd.serial_number, rd.registration_id, rd.utm_id, rd.specific_session_id from t_drone_location dl left join t_remote_data rd on dl.reservation_id = rd.uasl_reservation_id
and dl.get_location_timestamp >= #{startTime,jdbcType=TIMESTAMP}
and dl.get_location_timestamp <= #{endTime,jdbcType=TIMESTAMP}
and dl.reservation_id = #{reservationId,jdbcType=VARCHAR}
and dl.uasl_id = #{uaslId,jdbcType=VARCHAR}
and dl.operator_id = #{operatorId,jdbcType=VARCHAR}
and dl.aircraft_info_id = #{aircraftInfoId,jdbcType=INTEGER}
and dl.ua_type = #{uaType,jdbcType=VARCHAR}
order by dl.get_location_timestamp desc
